async (page) => {
  const result = await page.evaluate(() => {
    const p = window.game && window.game.player;
    if (!p) return 'no player';
    return JSON.stringify({
      weapon: p.equipments ? p.equipments[4] : null,
      weaponKey: p.weaponKey,
      allEquipments: p.equipments,
      skills: p.skills ? Object.fromEntries(Object.entries(p.skills).map(([k, v]) => [k, {level: v.level, exp: v.experience}])) : {},
      level: p.level,
      hp: p.hitPoints,
      maxHp: p.maxHitPoints,
    });
  });
  return result;
}
